def check_logical(self):
    """
    Build a line from tokens and run all logical checks on it.
    """
    self.build_tokens_line()
    self.report.increment_logical_line()

    first_line = self.lines[self.mapping[0][1][2][0] - 1]
    indent = first_line[:self.mapping[0][1][2][1]]
    self.previous_indent_level = self.indent_level
    self.indent_level = expand_indent(indent)

    if self.verbose >= 2:
        print((self.logical_line[:80].rstrip()))

    for name, check, argument_names in self._logical_checks:
        if self.verbose >= 4:
            print(('   ' + name))

        for offset, text in self.run_check(check, argument_names):
            if isinstance(offset, tuple):
                # Unpacking tuple for original number and offset
                orig_number, orig_offset = offset
            else:
                for token_offset, token in self.mapping:
                    # Using unpacking for `token` elements
                    (_, _, (token_number, token_offset_start)) = token
                    if offset >= token_offset:
                        orig_number = token_number
                        orig_offset = token_offset_start + offset - token_offset

            self.report_error(orig_number, orig_offset, text, check)

    self.previous_logical = self.logical_line

