def main():
    module = AnsibleModule(
        argument_spec=dict(
            path=dict(required=True, type='path'),
            follow=dict(default='no', type='bool'),
            get_md5=dict(default='yes', type='bool'),
            get_checksum=dict(default='yes', type='bool'),
            get_mime=dict(default=True, type='bool', aliases=['mime', 'mime_type', 'mime-type']),
            get_attributes=dict(default=True, type='bool', aliases=['attributes', 'attr']),
            checksum_algorithm=dict(default='sha1', type='str',
                                    choices=['sha1', 'sha224', 'sha256', 'sha384', 'sha512'],
                                    aliases=['checksum_algo', 'checksum']),
        ),
        supports_check_mode=True
    )

    path, follow, get_mime, get_attr, get_md5, get_checksum, checksum_algorithm = (
        module.params.get(key) for key in [
            'path', 'follow', 'get_mime', 'get_attributes', 'get_md5', 'get_checksum', 'checksum_algorithm'
        ]
    )

    b_path = to_bytes(path, errors='surrogate_or_strict')

    # main stat data
    try:
        st = os.stat(b_path) if follow else os.lstat(b_path)
    except OSError:
        e = get_exception()
        if e.errno == errno.ENOENT:
            output = {'exists': False}
            module.exit_json(changed=False, stat=output)

        module.fail_json(msg=e.strerror)

    # process base results
    output = format_output(module, path, st)

    # resolved permissions
    for perm_name, perm_flag in [('readable', os.R_OK), ('writeable', os.W_OK), ('executable', os.X_OK)]:
        output[perm_name] = os.access(path, perm_flag)

    # symlink info
    if output.get('islnk'):
        output['lnk_source'] = os.path.realpath(path)

    try:  # user data
        output['pw_name'] = pwd.getpwuid(st.st_uid).pw_name
    except:
        pass

    try:  # group data
        output['gr_name'] = grp.getgrgid(st.st_gid).gr_name
    except:
        pass

    # checksums
    if output.get('isreg') and output.get('readable'):
        if get_md5:
            # Will fail on FIPS-140 compliant systems
            try:
                output['md5'] = module.md5(path)
            except ValueError:
                output['md5'] = None

        if get_checksum:
            output['checksum'] = module.digest_from_file(path, checksum_algorithm)

    # try to get mime data if requested
    if get_mime:
        output['mimetype'], output['charset'] = 'unknown', 'unknown'
        mimecmd = module.get_bin_path('file')
        if mimecmd:
            mimecmd = [mimecmd, '-i', path]
            try:
                rc, out, err = module.run_command(mimecmd)
                if rc == 0:
                    mimetype, charset = (field.strip() for field in out.split(':')[1].split(';'))
                    output['mimetype'], output['charset'] = mimetype, charset.split('=')[1].strip()
            except:
                pass

    # try to get attr data
    if get_attr:
        output.update({'version': None, 'attributes': [], 'attr_flags': ''})
        out = module.get_file_attributes(path)
        for x in ('version', 'attributes', 'attr_flags'):
            if x in out:
                output[x] = out[x]

    module.exit_json(changed=False, stat=output)

